];

const dripSchedule = {
  1: { days: 1, subject: 'Here\'s what to expect this week', template: 'drip_day1' },
  2: { days: 3, subject: 'Please complete your intake form', template: 'drip_day3' },
  3: { days: 7, subject: 'Week 1 progress update', template: 'drip_week1' },
  4: { days: 14, subject: 'Halfway check-in', template: 'drip_week2' },
  5: { days: 21, subject: 'Final week — launch prep', template: 'drip_week3' },
  6: { days: 30, subject: 'You\'re live! Here\'s your retainer details', template: 'drip_launch' },
  7: { days: 45, subject: 'How\'s everything running?', template: 'drip_checkin' },
